#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for 微信私域运营 (企微 + 个人号 + 公众号 + 视频号 + 小程序 + 朋友圈 + 社群 全链路 — 引流 / 沉淀 / 触达 / 转化 / 复购 / 裂变).
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="微信私域运营 (企微 + 个人号 + 公众号 + 视频号 + 小程序 + 朋友圈 + 社群 全链路 — 引流 / 沉淀 / 触达 / 转化 / 复购 / 裂变)"
DIM_COUNT=6

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (6 个):
  9.1 平台合规红线与玩法保鲜期核查
  9.2 流量自主权与公转私漏斗诊断
  9.3 品类适配性与前置条件评估
  9.4 运营体系成熟度（工具 vs 运营 vs 人）
  9.5 流派定位识别
  9.6 工具栈选型与同质化避坑

背后的心智模型:
  • 公私二分 / 流量自主权（mental model）: 私域人看一切流量的底层镜片是「这部分流量是租来的还是自己的」——租来的（公域）用一次付一次、平台控分发，自己的（私域）可反复免费触达；近年这对二分从「对立」演化为「全域协同」，但「自主权」这条轴没变。
  • 流量池 / 蓄水养鱼（mental model）: 私域人把流量当成「要蓄进池子、反复经营」的对象而非「这次能转化多少」的一次性曝光——但「建了群 / 加了好友」只是蓄了水，**没有运营动作的池是死水**；价值在「蓄水—养鱼—捕鱼」的循环，不在池子大小
  • 精细化分层 / 用户是 N 个分层（mental model）: 私域人默认「用户不是一群人，是 N 个分层」——按生命周期阶段 × 价值 × 意向 × 活跃度多维分群，对不同层用不同动作；**全员一套话术是这一行最高频的死法**。

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "平台合规红线与玩法保鲜期核查"
  "流量自主权与公转私漏斗诊断"
  "品类适配性与前置条件评估"
  "运营体系成熟度（工具 vs 运营 vs 人）"
  "流派定位识别"
  "工具栈选型与同质化避坑"
)
declare -a DIM_QUESTIONS=(
  "用户打算用的具体玩法 / 动作（裂变形态、自动化加好友、群发频次、朋友圈打卡、个人号多开）踩不踩微信当前红线；该玩法距上次验证多久（> 3-6 个月默认作废）；引用的平台规则条款编号是否仍是官网当前版本。"
  "用户当前流量的所有权归谁（自有 / 平台租用）；公转私漏斗逐环转化率（曝光 → 扫码 → 添加 → 通过 → 破冰留存）哪一环漏损最大；承接 SOP 是否存在（钩子是否兑现、欢迎语是否打标）；是否分渠道活码（能否归因）。"
  "品类是否适合私域（复购频次 / 客单价 / 决策链长度——高复购、高客单、决策链长更适合）；三个前置条件是否齐备（稳定公域流量来源、能持续产内容的人、客单价能否覆盖私域人力成本）；是否属于「不适合私域的 70% 商家」。"
  "用户是「买了工具就以为有私域」还是「有 SOP / 团队 / 标签分层」；池子是死水还是有「蓄水—养鱼—捕鱼」循环；是否过度铺触点 / 过早求全（该用最小版本验证的阶段在做全套）；私域是否绑死在一个人身上（有没有 SOP 文档化）。"
  "用户当前打法的术语组合和价值取向，反推他属于哪个流派——增长/工具派（密集说 SCRM / 自动化 / 中台）、复购/会员（品牌）派（LTV / 用户资产 / 长期价值）、媒体/操盘手派（拆案例 / 操盘手共创）、社群/IP 派（群活跃 / 破冰 / 私域 IP）、平台派（合规优先 / 企微 default）、运营通识派（流量变现链条）；用户的诉求和他实际该走的路是否匹配。"
  "主战场是否企微（不是个人号）；企微 SCRM / 电商 SaaS 是不是只装一个（同质工具别同时上）；工具是否过了「合规资质 + 会话存档」门槛；AI 能力层处于「卖点」还是「标配」阶段；是否把公域数据工具（飞瓜 / 新榜）误当私域工具。"
)
declare -a DIM_SOURCES=(
  "微信外部链接内容管理规范原文（weixin.qq.com/agreement/...）、企业微信用户账号使用规范（work.weixin.qq.com/nl/norm）、企业微信违规场景及处罚规则；微信公开课 PRO / 企业微信生态大会近一年政策发布；不看课程文章和 3 个月前的裂变模板。"
  "用户自己的企微 / SCRM 后台数据（各渠道加粉量与成本、7 日留存率）；T03 W2 公转私漏斗 SOP 的步骤骨架；见实大会的品牌承接案例（比 vendor 中立）；不看「加粉总数」这种单一数字。"
  "用户自己的品类复购数据和成本结构；T03 W1 0→1 冷启动的「品类判断 + 前置条件」资深路径；晏涛《超级用户增长》的品类适配讨论；intake warnings「头部 vs 腰部断层」；不看「人人都能做私域」的课程话术。"
  "用户的实际运营动作清单（有没有 1v1 SOP / 社群 SOP / 朋友圈内容表 / 分层动作）；T03 八个 workflow 的「入门 SOP vs 资深路径」对照；T02 避坑「买了 SCRM≠私域」；见实 / 群响语境的「先裸跑再上工具」路径。"
  "用户自己描述需求时用的词（T06 给的「多流派术语偏好」语言层证据）；T01 figures 的流派归属 + T04/T07 智识谱系；不看「我们要做私域」这种没有流派信息的笼统表述。"
  "T02 选型决策树 A/B + 前置硬规则 + 避坑清单；各 vendor 官网（surrogate_primary，需对冲）+ 36氪 / IT之家第三方盘点（带厂商立场）；不看知乎 / CSDN / woshipm 的工具对比（黑名单）。"
)
declare -a DIM_OUTPUT_FORMATS=(
  "「该玩法当前合规状态：白帽 / 灰区（具体踩哪条边缘）/ 黑帽（违反规范第 X 条）；保鲜期评估：还可用 / 需重验 / 已失效；引用条款核对日期 YYYY-MM-DD」。"
  "「流量自主权评级：高 / 中 / 低（含理由）；漏斗最大漏损环：{引流/承接/触达/转化/复购}，转化率 X%；承接 SOP 状态：完整 / 缺失；归因能力：分渠道可归因 / 一个共享码不可归因」。"
  "「品类适配性：适合 / 勉强 / 不适合（含复购·客单·决策链三维判断）；前置条件缺口：{公域来源/内容产能/人力成本覆盖} 缺哪些；建议：硬启动 / 先补前置条件 / 不建议做私域」。"
  "「运营体系成熟度：工具阶段（只有工具没动作）/ SOP 阶段（有动作没体系）/ 体系阶段（可复制、不依赖单人）；过度设计风险：有（具体哪里铺太大）/ 无；下一步重点：补 SOP / 拆组织 / 收缩摊子」。"
  "「用户流派定位：{流派名}（依据：用了哪些术语 + 什么价值取向）；该流派的盲区：{对应分歧里这一派容易忽略的}；建议补充视角：{对立派的哪条主张值得参考}」。"
  "「主战场：企微 / 个人号（过时）；SCRM 选型建议：{具体一家 + 理由，或『现有够用不必换』}；同质工具冗余风险：有（同时装了 X 和 Y）/ 无；合规门槛：通过 / 不通过；提醒：该结论保鲜期 3-6 个月，需复验」。"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
